VALUES
  ('cpa-moex-00221', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A證券商因其業務員買賣有價證券下單操作失誤造成客戶甲之損失。甲乃向法院起訴A證券商應 賠償其損失。基於下列何種理由，A證券商能請求法院不經實體審查而駁回甲之訴訟？', '["A證券商與甲有仲裁約定", "A證券商與甲有擔保合意", "A證券商之業務員操作並無過失", "甲無法證明其損失數額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00222', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '為落實股東行動主義，甲擬徵求A公開發行公司（下稱「A公司」）出席股東會之委託書，徵求 行為應遵守法令規範，下列有關委託書之敘述，何者錯誤？', '["甲除代為發放股東紀念品或徵求人支付予代為處理徵求事務者之合理費用，不得為以給付金錢 或其他利益價購為條件", "A公司股東乙臨時找不到公司印發之委託書，而自行用信紙寫一封委託書，該委託書屬違法", "甲持未遵守法令規範之徵求委託書出席股東會行使表決權，該次股東會決議因此無效", "A公司股東甲應於股東常會開會38日前檢附相關委託書徵求資料表等文件，送達公司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00223', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司為科技業大廠，甲為公司之董事，其因私人因素擬轉讓手上的持股，關於其持股轉讓 限制方式，下列敘述何者錯誤？', '["甲得於向主管機關申報之日起3日後，向符合主管機關所訂條件之特定人為之", "甲於集中交易市場中，每日交易不超過10張者，得豁免轉讓方式限制", "甲得經主管機關核准或自申報主管機關生效日後，向非特定人為之", "甲得依主管機關所定持有期間及每一交易日得轉讓數量比例，於向主管機關申報之日起3日後， 於集中交易市場或證券商營業處所為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00224', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲為上市公司A之董事長，A公司準備募集股票籌資，而甲知道必須向認股人交付公開說明書， 但他對公開說明書主要內容不實之民事責任並不清楚，甲下列認知何者錯誤？', '["甲自己應負無過失責任", "A公司應負無過失責任", "該股票承銷商得主張已盡相當注意，並有正當理由相信無虛偽而免負賠償責任", "在公開說明書上簽章的職員得主張已盡相當注意，並有正當理由相信無虛偽而免負賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00225', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司（下稱「A公司」）辦理現金發行新股，保留法定比例予員工優先認購後，再經董事會 決議提撥發行新股總額15%對外公開發行，剩餘股數則由原股東認購，該公司股東並全數認購。 A公司上述發行新股之程序，存在何種錯誤？', '["現金發行新股適用股權分散之規定", "員工須於股權分散後始可行使新股認購權", "董事會無權將股權分散比例定為15%", "股東之認購權不應優先於股權分散"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00226', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依現行證券交易法規定，公開發行公司獨立董事甲若於任期中與該公司非獨立董事乙結婚，下列 敘述何者正確？', '["該獨立董事甲不得與同公司非獨立董事乙結婚", "該獨立董事甲於結婚後應視為非獨立董事", "該獨立董事甲結婚後，恐喪失董事資格", "該獨立董事甲應經股東會決議轉任為非獨立董事"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00227', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司（下稱「A公司」）的董事甲於今年1月中旬自集中交易市場買進A公司股票，之後 在今年3月下旬又從集中交易市場賣出A公司股票，共計獲利新臺幣1百萬元。由於A公司董 事會不為公司行使歸入權，請求甲將其利益歸於公司。該公司的股東乙乃依法請求董事會為公司 行使歸入權。依證券交易法之規定，A公司董事會於乙請求後幾日之限期內不行使時，則乙得為 公司行使歸入權？', '["10日", "15日", "30日", "60日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00228', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲剛擔任A上櫃公司（下稱「A公司」）的董事，由於他聽說證券交易法禁止內線交易，所以想 要知道相關規範。依證券交易法第157條之1條文規定，下列敘述何者正確？', '["若甲知悉 A 公司有重大影響其支付本息能力之消息，在該消息未公開前買進 A 公司普通公司 債，並不會構成內線交易", "若甲知悉 A 公司有重大影響其支付本息能力之消息，在該消息未公開前賣出 A 公司普通公司 債，並不會構成內線交易", "若甲辭去A公司董事後，就不是證券交易法內線交易之規範對象", "若甲知悉A公司的內線消息，在該消息公開後，立刻買賣A公司股票，並不會構成內線交易"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00229', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於公開發行公司年度財務報告，合併財務報告應重行編製之標準，下列敘述何者正確？', '["更正綜合損益金額在新臺幣1千萬元以上，且達原決算營業收入淨額百分之一者", "更正綜合損益金額在新臺幣1千5百萬元以上，且達原決算營業收入淨額百分之一點五者", "更正資產負債表個別項目（不含重分類）金額在新臺幣1千5百萬元以上，且達原決算總資產 金額百分之一點五者", "更正資產負債表個別項目（不含重分類）金額在新臺幣1千萬元以上，且達原決算總資產金額 百分之一者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00230', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依商業會計法之規定，使用電子方式處理會計資料之商業，會讓會計人員被處5年以下有期徒刑、', '["故意輸入不實資料", "故意塗改貯存體之會計資料，使財務報表不實", "故意遺漏會計事項不為登錄，使財務報表不 實", "其他利用不正當方法，使會計事項不實"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
